
-- Expand policy catalog with comprehensive global policies from shared data assets
INSERT INTO policy_catalog (policy_key, title, category, jurisdiction, framework, description, mandatory_for, template_content, checklist_items, is_featured, complexity_level, estimated_hours) VALUES
-- EU/GDPR Comprehensive Policies
('eu_isms_charter', 'Information Security Management System Charter', 'security', 'EU', 'ISO27001+NIS2', 'Establishes governance, accountability, and improvement cycle for information security aligned with ISO/IEC 27001 and NIS2 directive', '["large-scale_monitoring", "essential_services", "digital_service_providers"]', 'ISMS Charter\n\nDocument Owner: Chief Information Security Officer (CISO)\nApproved By: Board of Directors\nEffective Date: [DD/MM/YYYY]\nReview Cycle: Annual\n\nPurpose\nThis ISMS Charter establishes the framework, responsibilities, and principles for the management of information security at [Company Name]. It ensures the confidentiality, integrity, and availability of information assets in alignment with ISO/IEC 27001 and the EU NIS2 Directive.\n\nScope\nApplies to:\n- All employees, contractors, and third-party service providers\n- All systems, applications, and data owned or processed by [Company Name]\n\nPrinciples\n- Risk-Based Approach: Regular risk assessments to identify and treat risks\n- Governance: The CISO reports quarterly to the Board on ISMS performance\n- Continuous Improvement: ISMS effectiveness is reviewed annually\n- Compliance: The ISMS supports compliance with GDPR, NIS2, and contractual obligations\n\nResponsibilities\n- Board of Directors: Oversight and approval of ISMS policy and budget\n- CISO: Implementation, monitoring, and continuous improvement of ISMS\n- Employees & Contractors: Adherence to security policies and training', '["Assign CISO role", "Define information assets", "Conduct risk assessment", "Implement ISO27001 controls", "Establish quarterly board reporting", "Plan annual ISMS review", "Document security responsibilities", "Implement security awareness training"]', 1, 'advanced', 8.0),

('eu_dpo_role_policy', 'Data Protection Officer Role Policy', 'privacy', 'EU', 'GDPR', 'Defines the role, independence, and authority of the DPO in line with Articles 37-39 GDPR', '["public_authorities", "large_scale_monitoring", "sensitive_data_processing"]', 'Data Protection Officer (DPO) Role Policy\n\nAppointed DPO: [Full Name]\nContact: [DPO Email/Phone]\nEffective Date: [DD/MM/YYYY]\n\nPurpose\nThis policy defines the role, independence, and authority of the DPO in line with Articles 37–39 GDPR.\n\nAppointment & Independence\n- The DPO is appointed by [Company Name]s Board\n- The DPO reports directly to senior management and operates independently\n- The DPO will not receive instructions on the exercise of their duties and will not be penalized for performing them\n\nResponsibilities\n- Monitor compliance with GDPR, NIS2, and internal policies\n- Advise on Data Protection Impact Assessments (DPIAs)\n- Act as contact point for supervisory authorities and data subjects\n- Provide data protection awareness training\n\nAccessibility\n- DPO contact details published in privacy policy\n- Direct access for data subjects and supervisory authorities', '["Appoint qualified DPO", "Ensure DPO independence", "Define reporting structure", "Document DPO responsibilities", "Establish DPO contact channels", "Plan DPO training programs", "Create DPIA process", "Set up supervisory authority liaison"]', 1, 'intermediate', 4.0),

('eu_incident_response_plan', 'EU Incident Response Plan', 'security', 'EU', 'GDPR+NIS2', 'Comprehensive incident response plan covering GDPR breach notification and NIS2 incident reporting requirements', '["all_data_controllers", "essential_services", "digital_service_providers"]', 'Incident Response (IR) Plan\n\nOwner: Security Operations Center (SOC) / CISO\nEffective Date: [DD/MM/YYYY]\n\nObjectives\nTo ensure timely, coordinated, and compliant handling of security and privacy incidents.\n\nPhases\n1. Identification – Detection, classification, and logging of incident\n2. Containment – Immediate action to prevent further harm\n3. Investigation – Root cause analysis, impact assessment\n4. Notification –\n   - Supervisory Authority: within 72 hours of awareness (GDPR Art. 33)\n   - Data Subjects: without undue delay if high risk (GDPR Art. 34)\n   - NIS2: initial notification within 24 hours, final report within 72h\n5. Eradication & Recovery – Remove threat, restore systems\n6. Lessons Learned – Post-mortem review, update controls\n\nRoles\n- Incident Manager: [Name/Role]\n- Communications Lead: [Name/Role]\n- Legal & DPO: Ensure compliance with GDPR/NIS2 notification duties', '["Establish 24/7 incident detection", "Define incident classification", "Create incident response team", "Implement 72-hour notification process", "Develop incident communication templates", "Establish evidence preservation procedures", "Create post-incident review process", "Test incident response plan quarterly"]', 1, 'advanced', 6.0),

-- US Compliance Policies
('us_ccpa_privacy_policy', 'CCPA/CPRA Privacy Policy', 'privacy', 'US', 'CCPA', 'California Consumer Privacy Act compliant privacy policy with CPRA amendments', '["california_businesses", "personal_data_processors"]', 'Privacy Policy (CCPA/CPRA-Compliant)\n\nPublished By: [Company Name]\nEffective Date: [DD/MM/YYYY]\nContact: [Privacy Contact, Email, Address]\n\nScope\nThis Privacy Policy applies to California residents under the California Consumer Privacy Act (CCPA), as amended by the California Privacy Rights Act (CPRA), and other applicable US privacy laws.\n\nData We Collect\n- Personal Identifiers (name, email, phone)\n- Financial Information (credit card, account numbers)\n- Commercial Information (purchase history)\n- Internet/Device Data (cookies, usage, IP address)\n\nConsumer Rights (California Residents)\n- Right to Know what personal data is collected, sold, or shared\n- Right to Delete personal information\n- Right to Opt-Out of Sale or Sharing of personal data\n- Right to Correct inaccurate personal information\n- Right to Limit use of sensitive personal information\n\nNon-Discrimination\n[Company Name] will not discriminate against consumers for exercising their privacy rights.', '["Identify covered personal information", "Implement consumer rights processes", "Create opt-out mechanisms", "Establish verification procedures", "Document data collection purposes", "Implement non-discrimination measures", "Create consumer request portal", "Establish deletion procedures"]', 1, 'intermediate', 5.0),

('us_hipaa_policy', 'HIPAA Privacy & Security Policy', 'healthcare', 'US', 'HIPAA', 'Health Insurance Portability and Accountability Act compliance for healthcare data', '["covered_entities", "business_associates", "healthcare_providers"]', 'HIPAA Privacy & Security Policy\n\nOwner: HIPAA Privacy Officer\nEffective Date: [DD/MM/YYYY]\n\nPurpose\nTo comply with the Health Insurance Portability and Accountability Act (HIPAA) Privacy, Security, and Breach Notification Rules.\n\nKey Principles\n- Minimum Necessary: Limit PHI use to minimum required\n- Access Controls: Unique IDs, role-based access, audit logs\n- Safeguards: Administrative, technical, and physical safeguards\n- Breach Notification: Notify HHS within 60 days (or immediately if >500 records affected)\n\nAdministrative Safeguards\n- Assign HIPAA Security Officer\n- Conduct workforce training\n- Information access management\n- Security awareness and training\n\nPhysical Safeguards\n- Facility access controls\n- Workstation use restrictions\n- Device and media controls\n\nTechnical Safeguards\n- Access control and unique user identification\n- Audit controls and data integrity\n- Person or entity authentication\n- Transmission security', '["Appoint HIPAA officers", "Implement minimum necessary standard", "Establish access controls", "Create audit procedures", "Implement physical safeguards", "Establish breach notification process", "Conduct HIPAA training", "Create business associate agreements"]', 1, 'advanced', 7.0),

('us_pci_dss_policy', 'PCI DSS Compliance Policy', 'financial', 'Global', 'PCI DSS', 'Payment Card Industry Data Security Standard compliance for payment processing', '["payment_processors", "merchants", "service_providers"]', 'PCI DSS Compliance Policy\n\nOwner: Chief Financial Officer / IT Security\nEffective Date: [DD/MM/YYYY]\n\nScope\nAll systems, applications, and networks involved in payment card processing.\n\nRequirements\n1. Install and maintain a firewall configuration\n2. Do not use vendor-supplied defaults for system passwords\n3. Protect stored cardholder data\n4. Encrypt transmission of cardholder data across open, public networks\n5. Protect all systems against malware\n6. Develop and maintain secure systems and applications\n7. Restrict access to cardholder data by business need to know\n8. Identify and authenticate access to system components\n9. Restrict physical access to cardholder data\n10. Track and monitor all access to network resources and cardholder data\n11. Regularly test security systems and processes\n12. Maintain a policy that addresses information security\n\nCompliance Activities\n- Annual PCI DSS Self-Assessment or ROC (Report on Compliance)\n- Quarterly ASV scans and annual penetration tests\n- Cardholder data encryption (TLS 1.2+)\n- Network segmentation to isolate payment systems\n- Security awareness training for staff', '["Complete PCI DSS assessment", "Implement network segmentation", "Establish cardholder data encryption", "Conduct quarterly vulnerability scans", "Perform annual penetration testing", "Create incident response procedures", "Implement access controls", "Conduct security awareness training"]', 1, 'advanced', 10.0),

-- China Compliance Policies
('china_pipl_policy', 'Personal Information Protection Law Policy', 'privacy', 'China', 'PIPL', 'Compliance with Chinas Personal Information Protection Law including data localization requirements', '["china_data_processors", "cross_border_transfers"]', 'Privacy Policy (PIPL-Compliant)\n\nPublished By: [Company Name]\nEffective Date: [DD/MM/YYYY]\nContact: [Data Protection Officer / Contact Email]\n\nIntroduction\nThis Privacy Policy explains how [Company Name] collects, uses, stores, and protects personal data of users in China, in compliance with the Personal Information Protection Law (PIPL).\n\nData Collected\n- Personal Identifiers (name, ID number, phone, email)\n- Financial information (bank accounts, payment details)\n- Sensitive personal information (biometric data, health data)\n- Technical data (IP, device IDs, cookies)\n\nLegal Basis for Processing\n- Consent: explicit and informed consent from the individual\n- Contractual necessity: necessary for performance of a contract\n- Legal obligation: required by laws or government regulations\n\nUser Rights\n- Access, correction, deletion, and data portability\n- Right to withdraw consent at any time\n- Right to restrict or object to processing\n\nCross-Border Transfer\n- Must undergo security assessment or certification approved by authorities\n- Contracts with overseas recipients must include required safeguards (Articles 38–39 PIPL)\n\nData Retention\nOnly retain personal data as long as necessary to fulfill purposes, then securely delete or anonymize.', '["Implement explicit consent mechanisms", "Establish data localization procedures", "Create cross-border transfer assessments", "Implement data subject rights portal", "Establish local data representative", "Create security assessment procedures", "Implement immediate breach notification", "Establish consent withdrawal mechanisms"]', 1, 'advanced', 8.0),

('china_csl_policy', 'Cybersecurity Law Compliance Policy', 'security', 'China', 'CSL', 'Information security management policy compliant with Chinas Cybersecurity Law', '["network_operators", "critical_infrastructure", "china_operations"]', 'Information Security Management Policy (CSL-Compliant)\n\nOwner: Chief Information Security Officer (CISO)\nEffective Date: [DD/MM/YYYY]\n\nPurpose\nTo ensure all information systems comply with the Cybersecurity Law of China (CSL), including network security and critical information infrastructure protection.\n\nKey Controls\n- Network access control, monitoring, and logging\n- Data encryption at rest and in transit\n- Security testing and vulnerability management\n- Regular employee training on cybersecurity\n- Incident detection and response capability\n\nCritical Information Infrastructure (CII)\n- Enhanced security requirements for CII operators\n- Data localization requirements\n- Security assessment for cross-border data transfers\n- Annual security assessments by approved organizations\n\nNetwork Security Requirements\n- Real-name registration for network access\n- Log retention for at least 6 months\n- Incident reporting to authorities\n- Cooperation with national security investigations', '["Identify critical information infrastructure", "Implement network access controls", "Establish data localization procedures", "Create incident reporting mechanisms", "Implement real-name registration", "Establish log retention systems", "Conduct annual security assessments", "Create cooperation procedures with authorities"]', 1, 'advanced', 9.0),

-- Brazil LGPD Policies
('brazil_lgpd_policy', 'Lei Geral de Proteção de Dados Policy', 'privacy', 'Brazil', 'LGPD', 'Comprehensive LGPD compliance policy for Brazilian personal data protection', '["brazil_data_processors", "personal_data_handlers"]', 'Privacy Policy (LGPD-Compliant)\n\nPublished By: [Company Name]\nEffective Date: [DD/MM/YYYY]\nContact: [DPO Contact, Email, Address]\n\nIntroduction\nThis Privacy Policy explains how [Company Name] collects, uses, stores, and protects personal data of individuals in Brazil in accordance with the Lei Geral de Proteção de Dados (LGPD, Law No. 13,709/2018).\n\nData Collected\n- Identification (name, email, phone, CPF)\n- Financial data (bank accounts, credit cards)\n- Sensitive personal data (health, racial/ethnic origin, biometrics, religious beliefs)\n- Internet/device data (IP address, cookies, device info)\n\nLegal Basis for Processing\n- Consent: explicit and informed consent from the individual\n- Contractual necessity: processing required for execution of a contract\n- Legal obligation: processing required by law\n- Legitimate interest: limited processing for operational or security purposes\n\nData Subject Rights\n- Access, correction, deletion, anonymization, portability, and revocation of consent\n- Right to withdraw consent at any time\n- Right to refuse automated decisions with significant effects\n\nCross-Border Transfer\nPersonal data transferred abroad must meet LGPD adequacy requirements:\n- Adequate legal framework\n- Contractual safeguards\n- Consent of the data subject\n\nRetention\nRetain only as necessary to fulfill purposes; securely delete or anonymize afterward.', '["Implement LGPD consent mechanisms", "Establish ANPD reporting procedures", "Create data subject rights portal", "Implement cross-border transfer safeguards", "Establish DPO role and responsibilities", "Create incident notification procedures", "Implement data retention policies", "Establish automated decision opt-out"]', 1, 'intermediate', 6.0),

-- Singapore PDPA Policies
('singapore_pdpa_policy', 'Personal Data Protection Act Policy', 'privacy', 'Singapore', 'PDPA', 'Singapore PDPA compliance policy for personal data protection', '["singapore_organizations", "personal_data_processors"]', 'Privacy Policy (PDPA-Compliant)\n\nPublished By: [Company Name]\nEffective Date: [DD/MM/YYYY]\nContact: [DPO / Privacy Officer Contact]\n\nIntroduction\nThis Privacy Policy explains how [Company Name] collects, uses, discloses, and protects personal data in accordance with the Personal Data Protection Act (PDPA) 2012 of Singapore.\n\nData Collected\n- Personal identifiers (name, NRIC/FIN, email, phone)\n- Financial information (payment details, credit card, bank account)\n- Sensitive data (health, biometric, racial/ethnic data) – only collected with explicit consent\n- Technical data (IP address, device identifiers, cookies)\n\nPurpose of Collection\n- To provide services, process payments, and communicate with users\n- To comply with legal obligations\n- For operational or security purposes (legitimate interest)\n\nConsent\n- Personal data is collected with consent, except where PDPA allows otherwise\n- Consent withdrawal is allowed at any time; users can contact the DPO\n\nDisclosure\nData may be shared with vendors or third parties only for specified purposes and under contractual safeguards.\n\nRetention\n- Personal data is retained only as long as necessary for the purpose of collection\n- Secure destruction or anonymization occurs after retention period\n\nAccess & Correction\nUsers may request access to their data or corrections by contacting the DPO.', '["Implement PDPA consent framework", "Establish PDPC notification procedures", "Create access and correction procedures", "Implement purpose limitation controls", "Establish DPO mandatory role", "Create cross-border transfer safeguards", "Implement retention and destruction procedures", "Establish significant harm assessment"]', 1, 'intermediate', 5.0),

-- Global Multinational Policies
('global_vendor_risk_policy', 'Global Vendor Risk Management Policy', 'compliance', 'Global', 'Multi-jurisdictional', 'Comprehensive vendor risk management policy covering GDPR, CCPA, PIPL, LGPD, and PDPA requirements', '["all_organizations", "third_party_processors"]', 'Global Vendor / Third-Party Risk Management Policy\n\nOwner: Procurement / Risk Team\nEffective Date: [DD/MM/YYYY]\n\nPurpose\nEnsure all third parties globally comply with privacy and security obligations across multiple jurisdictions.\n\nRequirements\n- Vendor due diligence and risk assessment\n- Contracts include: confidentiality, breach notification, audit rights, and jurisdiction-specific clauses\n- Risk tiering: critical, high, medium, low\n- Annual review of critical vendors\n- Termination rights for non-compliance\n\nJurisdiction-Specific Requirements\n- EU: GDPR Article 28 Data Processing Agreements\n- US: CCPA service provider agreements, HIPAA Business Associate Agreements\n- China: PIPL cross-border transfer agreements\n- Brazil: LGPD processor agreements\n- Singapore: PDPA third-party disclosure agreements\n\nVendor Categories\n- Data Processors: Handle personal data on behalf of organization\n- Data Controllers: Process personal data for their own purposes\n- Service Providers: Provide technical or administrative services\n- Critical Infrastructure: Essential for business operations', '["Conduct vendor due diligence", "Implement jurisdiction-specific agreements", "Establish vendor risk tiering", "Create audit procedures", "Implement contract management", "Establish termination procedures", "Create vendor monitoring program", "Implement breach notification requirements"]', 1, 'advanced', 7.0),

('global_data_retention_policy', 'Global Data Retention & Destruction Policy', 'privacy', 'Global', 'Multi-jurisdictional', 'Comprehensive data retention policy balancing legal requirements across jurisdictions', '["all_data_controllers", "multinational_organizations"]', 'Global Data Retention & Destruction Policy\n\nOwner: Data Protection Officer / Legal\nEffective Date: [DD/MM/YYYY]\n\nPurpose\nMaintain data only as necessary and securely destroy it in compliance with jurisdictional laws.\n\nRetention Principles\n- Data minimization: Collect and retain only necessary data\n- Purpose limitation: Retain data only for original collection purpose\n- Legal compliance: Meet jurisdiction-specific retention requirements\n- Secure destruction: Use approved destruction methods\n\nJurisdiction-Specific Requirements\n- EU: GDPR storage limitation principle\n- US: Sector-specific requirements (HIPAA 6 years, financial records 7 years)\n- China: PIPL necessary period requirement\n- Brazil: LGPD purpose fulfillment requirement\n- Singapore: PDPA necessary period requirement\n\nData Categories & Retention\n- Personal Identifiers: As required by business purpose\n- Financial Records: 7 years (longest jurisdiction requirement)\n- Health Records: 6-30 years (jurisdiction dependent)\n- Marketing Data: Until consent withdrawn\n- Technical Logs: 6-24 months\n\nDestruction Methods\n- Physical media: Cross-cut shredding, incineration\n- Digital media: Cryptographic erasure, overwriting\n- Cloud storage: Certified deletion by provider\n- Backup systems: Automated deletion procedures', '["Define data categories", "Establish retention schedules", "Implement automated deletion", "Create destruction procedures", "Establish legal hold procedures", "Implement regular retention reviews", "Create destruction certification", "Establish cross-jurisdictional compliance"]', 1, 'intermediate', 5.0),

-- Specialized Industry Policies
('ai_governance_policy', 'AI Governance & Ethics Policy', 'governance', 'Global', 'AI Ethics', 'Comprehensive AI governance policy covering algorithmic accountability and bias prevention', '["ai_developers", "automated_decision_systems"]', 'AI Governance & Ethics Policy\n\nOwner: AI Ethics Committee / CTO\nEffective Date: [DD/MM/YYYY]\n\nPurpose\nEstablish principles and controls for responsible AI development, deployment, and governance.\n\nCore Principles\n- Transparency: AI systems should be explainable and auditable\n- Fairness: Prevent discrimination and bias in AI decisions\n- Accountability: Clear responsibility for AI system outcomes\n- Privacy: Protect personal data used in AI training and inference\n- Human Oversight: Meaningful human control over AI decisions\n\nAI Lifecycle Governance\n1. Design Phase: Ethics by design, bias assessment\n2. Development Phase: Diverse training data, bias testing\n3. Testing Phase: Fairness metrics, adversarial testing\n4. Deployment Phase: Human oversight, monitoring systems\n5. Monitoring Phase: Continuous bias detection, performance review\n\nHigh-Risk AI Systems\n- Automated hiring decisions\n- Credit scoring and financial decisions\n- Healthcare diagnosis and treatment\n- Criminal justice risk assessment\n- Biometric identification systems\n\nAI Impact Assessments\n- Required for high-risk AI systems\n- Assess bias, fairness, and discrimination risks\n- Document mitigation measures\n- Regular review and updates', '["Establish AI ethics committee", "Implement AI impact assessments", "Create bias testing procedures", "Establish human oversight mechanisms", "Implement transparency measures", "Create AI audit procedures", "Establish algorithmic accountability", "Implement continuous monitoring"]', 1, 'advanced', 8.0),

('blockchain_compliance_policy', 'Blockchain & Distributed Ledger Policy', 'technology', 'Global', 'Blockchain', 'Compliance policy for blockchain technology covering GDPR right to erasure challenges', '["blockchain_developers", "cryptocurrency_platforms"]', 'Blockchain & Distributed Ledger Policy\n\nOwner: Technology Team / Legal\nEffective Date: [DD/MM/YYYY]\n\nPurpose\nAddress compliance challenges unique to blockchain technology, particularly immutability vs. data subject rights.\n\nKey Challenges\n- Right to Erasure: Blockchain immutability vs GDPR Article 17\n- Data Minimization: Limited ability to modify recorded data\n- Cross-Border Transfers: Distributed nodes across jurisdictions\n- Controller/Processor Identification: Decentralized responsibility\n\nCompliance Strategies\n- Off-chain Storage: Store personal data off-chain with blockchain references\n- Encryption: Use encryption keys for effective data erasure\n- Pseudonymization: Implement strong pseudonymization techniques\n- Consent Management: Robust consent mechanisms for immutable recording\n\nTechnical Safeguards\n- Hash-only Storage: Store only cryptographic hashes on-chain\n- Private Keys: Use key deletion for functional data erasure\n- Permissioned Networks: Control access to sensitive data\n- Regular Audits: Monitor compliance across distributed systems\n\nGovernance Structure\n- Blockchain governance committee\n- Legal review for new blockchain implementations\n- Regular compliance assessments\n- Incident response for blockchain-specific issues', '["Implement off-chain personal data storage", "Establish encryption key management", "Create pseudonymization procedures", "Implement consent management", "Establish blockchain governance", "Create erasure procedures", "Implement cross-border compliance", "Establish node jurisdiction mapping"]', 0, 'advanced', 10.0),

('iot_privacy_policy', 'IoT Device Privacy & Security Policy', 'technology', 'Global', 'IoT Security', 'Privacy and security policy for Internet of Things devices and data collection', '["iot_manufacturers", "connected_device_operators"]', 'IoT Device Privacy & Security Policy\n\nOwner: Product Security Team\nEffective Date: [DD/MM/YYYY]\n\nPurpose\nEstablish privacy and security requirements for IoT devices and the data they collect.\n\nIoT Privacy Principles\n- Privacy by Design: Build privacy into IoT devices from conception\n- Data Minimization: Collect only necessary sensor data\n- Purpose Limitation: Use data only for stated purposes\n- Transparency: Clear information about data collection\n- User Control: Enable users to control their data\n\nDevice Security Requirements\n- Unique Device Identity: Each device has unique credentials\n- Encryption: All data transmission encrypted\n- Secure Boot: Verified software loading\n- Update Mechanism: Secure over-the-air updates\n- Default Security: Secure default configurations\n\nData Collection Controls\n- Sensor Data Governance: Control over sensor activation\n- Location Privacy: Geographic data protection\n- Behavioral Analytics: Limits on profiling\n- Third-Party Sharing: Restrictions on data sharing\n\nUser Rights & Controls\n- Device Discovery: Users can identify connected devices\n- Data Access: View collected data\n- Data Deletion: Delete device data\n- Opt-out: Disable data collection features\n- Portability: Export device data', '["Implement privacy by design", "Establish device security standards", "Create data collection controls", "Implement user consent mechanisms", "Establish device lifecycle management", "Create data minimization procedures", "Implement secure update mechanisms", "Establish IoT incident response"]', 0, 'intermediate', 6.0),

('biometric_data_policy', 'Biometric Data Protection Policy', 'privacy', 'Global', 'Biometric Privacy', 'Specialized policy for biometric data collection, processing, and protection', '["biometric_systems", "identity_verification"]', 'Biometric Data Protection Policy\n\nOwner: Privacy Officer / Security Team\nEffective Date: [DD/MM/YYYY]\n\nPurpose\nEstablish special protections for biometric identifiers and biometric information as sensitive personal data.\n\nBiometric Data Types\n- Physiological: Fingerprints, facial geometry, iris patterns, voice patterns\n- Behavioral: Typing patterns, gait analysis, signature dynamics\n- Biological: DNA, blood patterns, medical biometrics\n\nEnhanced Protections\n- Explicit Consent: Written consent required for biometric collection\n- Purpose Specification: Clear statement of biometric use purpose\n- Retention Limits: Delete biometric templates when no longer needed\n- Encryption: Strong encryption for biometric templates\n- Access Controls: Strict access controls for biometric data\n\nTechnical Safeguards\n- Template Protection: Store mathematical representations, not images\n- Liveness Detection: Prevent spoofing attacks\n- Multi-factor Authentication: Combine biometrics with other factors\n- Secure Transmission: Encrypted communication channels\n- Local Processing: Process biometrics locally when possible\n\nLegal Considerations\n- Illinois BIPA: 3-year retention limit, written consent\n- GDPR: Special category data requiring explicit consent\n- CCPA: Sensitive personal information protections\n- Sector-specific: Additional healthcare, financial regulations', '["Implement explicit consent procedures", "Establish biometric template protection", "Create retention and deletion procedures", "Implement liveness detection", "Establish access controls", "Create incident response for biometric breaches", "Implement local processing capabilities", "Establish legal compliance monitoring"]', 0, 'advanced', 7.0);
